/**
 * View modes for responsive display.
 */
export type ViewMode = 'full' | 'compact' | 'cards'

/**
 * Importance to visibility mapping.
 *
 * Determines which fields show in which view modes.
 */
export const importanceToVisibility: Record<string, ViewMode[]> = {
  primary: ['full', 'compact', 'cards'],
  secondary: ['full', 'compact'],
  tertiary: ['full'],
}

