/**
 * Get state style for an entity's state.
 */
export function getStateStyle(entity: string, state: string): StateStyle | undefined {
  return entityStateMachines[entity]?.styles[state]
}

/**
 * Check if a field should be visible in a view mode.
 */
export function isFieldVisible(importance: string, viewMode: ViewMode): boolean {
  return importanceToVisibility[importance]?.includes(viewMode) ?? false
}

/**
 * Get fields for a group in an entity.
 */
export function getFieldsInGroup(entity: string, group: string): string[] {
  return entityFieldGroups[entity]?.[group] ?? []
}